import{_ as s,c as i,a,o as n}from"./app-CEcM0piI.js";const d={};function l(t,e){return n(),i("div",null,e[0]||(e[0]=[a(`<p>![[Pasted image 20240301194110.png]] /bin：二进制可执行文件 /dev：设备文件 /etc：系统管理和配置文件 /home：用户主目录的起始基点 /lib：标准程序设计库 /sbin：系统管理命令 /tmp：公用的临时文件存贮点 /user：应用程序、软件包的配置文件 /var：某些大文件的溢出区</p><h1 id="命令入门" tabindex="-1"><a class="header-anchor" href="#命令入门"><span>命令入门</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>command [-options] [parameter]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>command：命令本身</li><li>-options：[可选,非必填]命令的一些选项,可以通过选项控制命令的行为细节</li><li>parameter：[可选,非必填]命令的参数,多数用于命令的指向目标等 <mark>语法中的[ ]，表示可选的意思</mark></li></ul><p>示例:</p><ul><li><code>ls-l/home/itheima</code> ls是命令本身，-l是选项，/home/itheima是参数意思是以列表的形式，显示/home/itheima目录内的内容</li><li><code>cp-rtest1 test2</code> cp是命令本身，-r是选项，test1和test2是参数意思是复制文件夹test1 成为 test2</li></ul><h1 id="ls显示指令" tabindex="-1"><a class="header-anchor" href="#ls显示指令"><span>ls显示指令</span></a></h1><p>ls命令的作用是列出目录下的内容 语法细节如下:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>1s[-a -l -h] [Linux路径]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-a-l-h是可选的选项 -a是all的意思，表示列出全部文件（包含隐藏文件和文件夹） <strong>Linux系统中以.开头的文件或文件夹默认被隐藏</strong> -l是list的意思，表示以列表的形式展示内容，并展示更多信息 选项可以组合使用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ls -a -l</span></span>
<span class="line"><span>ls -al</span></span>
<span class="line"><span>ls -la</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>效果都是一样的</p><p><strong>使用-l显示出来的列表中以d开头的表示文件夹，以-开头的表示文件</strong></p><p>-h需要和-l搭配使用，以更人性化的方式显示文件的大小单位</p><p>Linux路径是此命令可选的参数 当不使用选项和参数,直接使用ls命令本体,表示以平铺形式,列出当前工作目录下的内容 加上参数表示列出指定目录下的内容，如：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ls /home            列出home目录下的内容</span></span>
<span class="line"><span>ls /               列出根目录下的内容</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="目录相关" tabindex="-1"><a class="header-anchor" href="#目录相关"><span>目录相关</span></a></h1><h2 id="cd切换目录" tabindex="-1"><a class="header-anchor" href="#cd切换目录"><span>cd切换目录</span></a></h2><p>change directory</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cd [Linux路径]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>cd命令直接执行表示回到用户的home目录 cd加路径表示切换到目标目录（以/开头表示绝对路径，相对路径不需要输入/）</p><h4 id="特殊路径符" tabindex="-1"><a class="header-anchor" href="#特殊路径符"><span>特殊路径符</span></a></h4><ul><li>. 表示当前目录 如：cd ./Desktop 表示切换到当前目录下的Desktop目录内，和cd Desktop效果一致</li><li>.. 表示上一级目录 如：cd.. 切换到上一级目录，cd ../.. 切换到上两级目录</li><li>~表示home目录， 如：cd~ 切换到home目录 或cd ~/Desktop切换到home内的Desktop目录</li></ul><h2 id="pwd展示目录" tabindex="-1"><a class="header-anchor" href="#pwd展示目录"><span>pwd展示目录</span></a></h2><p>print work directory</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>pwd</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="mkdir创建目录" tabindex="-1"><a class="header-anchor" href="#mkdir创建目录"><span>mkdir创建目录</span></a></h2><p>make directory</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>mkdir [-p] Linux路径</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>mkdir ./test         表示在当前目录下创建名为test的文件夹</span></span>
<span class="line"><span>mkdir /home/pink/test       表示在pink目录下创建名为test的文件夹</span></span>
<span class="line"><span>mkdir ~/test          表示在home目录下创建名为test的文件夹</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>-p表示自动创建不存在的父目录，适用于创建连续多层级的目录</p><p>创建文件夹需要修改权限，尽量在home目录内创建，不要再home外操作 涉及到权限问题home外无法成功</p><h1 id="文件操作" tabindex="-1"><a class="header-anchor" href="#文件操作"><span>文件操作</span></a></h1><h2 id="touch创建文件" tabindex="-1"><a class="header-anchor" href="#touch创建文件"><span>touch创建文件</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>touch Linux路径</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="cat查看文件内容" tabindex="-1"><a class="header-anchor" href="#cat查看文件内容"><span>cat查看文件内容</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cat Linux路径</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="more查看文件内容" tabindex="-1"><a class="header-anchor" href="#more查看文件内容"><span>more查看文件内容</span></a></h2><p>more命令同样可以查看文件内容，与cat不同的是： cat是直接将内容全部显示出来 more支持翻页，如果文件过多可以一页一页展示</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>more Linux路径</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>more展示出内容后按空格翻页查看，按回车按行查看 按b翻上一页 按q退出查看</p><h2 id="cp复制文件-文件夹" tabindex="-1"><a class="header-anchor" href="#cp复制文件-文件夹"><span>cp复制文件\\文件夹</span></a></h2><p>copy</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cp [-r] 参数1 参数2</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-r：用于复制文件夹使用，表示递归（对于复制多层的文件夹使用） 参数1：Linux路径，表示被复制的文件或文件夹 参数2：Linux路径，表示复制到目标的地方</p><p>可复制到同目录文件夹并改名</p><h2 id="mv移动文件或文件夹" tabindex="-1"><a class="header-anchor" href="#mv移动文件或文件夹"><span>mv移动文件或文件夹</span></a></h2><p>move</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>mv 参数1 参数2</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>参数1：Linux路径，表示被复制的文件或文件夹 参数2：Linux路径，表示复制到目标的地方 如果目标不存在mv有一个改名的效果确保目标存在</p><h2 id="rm删除文件-文件夹" tabindex="-1"><a class="header-anchor" href="#rm删除文件-文件夹"><span>rm删除文件\\文件夹</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>rm [-r -f] 参数1 参数2 …… 参数n</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>和cp一样-r用于删除文件夹 -f：表示force，强制删除（不会弹出提示确认信息），（在root用户删除操作时会弹出提示询问是否删除输入y表示删除，n表示取消） 普通用户删除内容不会弹出提示，只有root管理员用户删除内容会有提示（一般用户用不到-f选项） 参数表示要删除的文件或文件夹路径，可多参数批量删除 rm命令可以使用通配符来做模糊匹配 rm -rf/ 和rm -rf/* 删除Linux系统所有内容</p><h1 id="通配符" tabindex="-1"><a class="header-anchor" href="#通配符"><span>通配符*</span></a></h1><p>符号* 表示通配符，即匹配任意内容（包含空） test* ：表示匹配任意以test开头的内容 *test：表示匹配任何以test结尾的内容 *test*：表示匹配任何包含test的内容</p><p>su - root 并输入密码可临时使用root权限 使用exit退回普通用户</p><h1 id="查找命令" tabindex="-1"><a class="header-anchor" href="#查找命令"><span>查找命令</span></a></h1><h2 id="which查找命令的命令" tabindex="-1"><a class="header-anchor" href="#which查找命令的命令"><span>which查找命令的命令</span></a></h2><p>Linux命令本质上都是二进制可执行程序</p><p>使用which可查看所使用的一系列命令的程序文件存放在哪里</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>which 要查找的内容</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="find查找文件" tabindex="-1"><a class="header-anchor" href="#find查找文件"><span>find查找文件</span></a></h2><h3 id="按文件名查找文件" tabindex="-1"><a class="header-anchor" href="#按文件名查找文件"><span>按文件名查找文件</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>find 起始路径 -name &quot;被查找文件名&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>起始路径表示从哪里开始搜索 也可以使用通配符进行搜索</p><h3 id="按文件大小查找文件" tabindex="-1"><a class="header-anchor" href="#按文件大小查找文件"><span>按文件大小查找文件</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>find 起始路径 -size +|-n[kMG]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>+、-表示大于和小于 n表示大小数字 kMG表示大小单位。k（小写）表示kb，M表示MB，G表示GB</p><p>示例： 从根目录中查找小于10kb的文件：find / -size -10k 查找大于100MB的文件：find / -size +100M 查找大于1GB的文件：find / -size +1G</p><h3 id="按文件类型查找" tabindex="-1"><a class="header-anchor" href="#按文件类型查找"><span>按文件类型查找</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>find 起始路径 -type 类型名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><table><thead><tr><th>文件类型</th><th>类型的字符描述</th></tr></thead><tbody><tr><td>普通文件类型</td><td>f</td></tr><tr><td>目录类型</td><td>d</td></tr><tr><td>软连接类型</td><td>l</td></tr><tr><td>字符设备类型</td><td>c</td></tr><tr><td>块设备类型</td><td>b</td></tr><tr><td>管道类型</td><td>p</td></tr><tr><td>本地套接字类型</td><td>s</td></tr></tbody></table><h2 id="目录层级" tabindex="-1"><a class="header-anchor" href="#目录层级"><span>目录层级</span></a></h2><p>目录可能有很多层, 在搜索某些属性的时候可以指定只搜索某几层目录, 相关的参数有两个, 分别为: <code>-maxdepth</code>和<code>-mindepth</code>。 这两个参数不能单独使用， 必须和其他属性一起使用，也就是搜索某几层目录中满足条件的文件。</p><ul><li><code>-maxdepth</code>: 最多搜索到第多少层目录 ,</li><li><code>-mindepth</code>: 至少从第多少层开始搜索</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span># 查找文件, 从根目录开始, 最多搜索5层, 这个文件叫做 *.txt (1 &lt;= 层数 &lt;= 5)  </span></span>
<span class="line"><span>sudo find / -maxdepth 5 -name &quot;*.txt&quot;  </span></span>
<span class="line"><span># 查找文件, 从根目录开始, 至少从第5层开始搜索, 这个文件叫做 *.txt (层数&gt;=5层)  </span></span>
<span class="line"><span>sudo find / -mindepth 5 -name &quot;*.txt&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="同时执行多个操作" tabindex="-1"><a class="header-anchor" href="#同时执行多个操作"><span>同时执行多个操作</span></a></h2><p>find无法配合管道符工作，但若想实现其需求可以使用exec、ok、xargs选项</p><h3 id="exec" tabindex="-1"><a class="header-anchor" href="#exec"><span>exec</span></a></h3><p><code>-exec</code> 是find的参数, <code>可以在exec参数后添加其他需要被执行的shell命令</code>。 find 添加了 exec 参数之后, 命令的<code>尾部需要加</code>一个后缀 <code>{} \\;</code>, 注意 <code>{}</code>和<code>\\</code>之间需要有一个空格。 在参数<code>-exec</code>后添加的shell命令处理的是find搜索之后的结果, find的结果会作为 新添加的shell命令 的输入，最后在终端上输出最终的处理结果。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ind 路径 参数 参数值 -exec shell命令2 {} \\</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="ok" tabindex="-1"><a class="header-anchor" href="#ok"><span>ok</span></a></h3><p><code>-ok</code> 和 <code>-exec</code> 都是<code>find</code>命令的参数, 使用方式类似, 但是这个参数是交互式的, 在处理<code>find</code>的结果的时候, 会向用户发起询问，比如在删除搜索结果的时候，为了保险起见，就需要询问机制了。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>find 路径 参数 参数值 -ok shell命令2 {} \\</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="xargs" tabindex="-1"><a class="header-anchor" href="#xargs"><span>xargs</span></a></h3><p>在使用<code>find</code>的<code>-exec</code>参数的时候, 需要在指定的子命令尾部添加几个特殊字符<code>{} \\;</code>，一不小心就容易写错，有一种看起来更加直观、书写更加简便的方式，我们可以使用 <code>xargs</code>替换掉<code>-exec</code>参数, 而且在处理数据的时候<code>xargs更高效</code>。有了<code>xargs</code>的加持我们就可以在<code>find</code>命令中直接使用管道完成前后命令的数据传递</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>find 路径 参数 参数值 | xargs shell命令2</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>xargs的效率比使用 -exec 效率高<br> -exec: 将find查询的结果逐条传递给后边的shell命令<br> -xargs: 将find查询的结果一次性传递给后边的shell命令</p><h2 id="grep过滤文件内容" tabindex="-1"><a class="header-anchor" href="#grep过滤文件内容"><span>grep过滤文件内容</span></a></h2><p>从文件中通过关键字过滤文件行</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>grep [-n] 关键字 文件路径</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-n表示在结果中显示匹配的行的行号 关键字：表示过滤的关键字，带有空格或其它特殊符号，建议使用””将关键字包围起来 文件路径：表示要过滤内容的文件路径，可作为内容输入端口</p><h2 id="local" tabindex="-1"><a class="header-anchor" href="#local"><span>local</span></a></h2><p>我们可以将<code>locate</code>看作是一个简化版的<code>find</code>, 使用这个命令我们可以<code>根据文件名搜索本地的磁盘文件</code>, 但是<code>locate的效率比find要高很多</code>。原因在于它不搜索具体目录，而是搜索一个本地的数据库文件，这个数据库中含有本地所有文件信息。Linux系统自动创建这个数据库，并且每天自动更新一次，所以使用locate命令查不到最新变动过的文件。为了避免这种情况，<code>可以在使用locate之前，先使用updatedb命令，手动更新数据库。</code> 使用管理员权限更新本地数据库文件, 非root用户需要加 sudo</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>updatedb</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol><li>搜索所有目录下以某个关键字开头的文件</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>locate 路径名/关键字 [-i\\n\\r]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>搜索指定路径下以该关键字开头的文件。路径必须为绝对路径，若不指定路径则默认是所有路径</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>locate /home/robin/test    # 指定搜索目录为 /home/robin/, 文件以 test 开头</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-i：忽略文件名的大小写</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>locate TEST -i	# 文件名以小写的test为前缀的文件也能被搜索到</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-n：列出前N个匹配到的文件名称或路径名称</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>locate test -n 5		# 搜索文件前缀为 test 的文件, 并且只显示5条信息</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-r：基于<code>正则表达式</code>进行文件名匹配, 查找符合条件的文件</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>locate -r &quot;\\.cpp$&quot;		# 搜索以 .cpp 结尾的文件</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><blockquote><p>[!important] 正则表达式小科普:</p><ol><li>在正则表达式中 <code>.</code>可以匹配任意一个 非 <code>\\n</code>的单字符</li><li>上边的命令中使用转译字符<code>\\</code>对特殊字符<code>.</code>转译, 就得到了普通的字符<code>.</code></li><li>在正则表达式中 <code>$</code>放到字符尾部, 表示字符串必须以这个字符结尾, 上边的命令中修饰的是字符<code>p</code></li><li>正则表达式中的 字符<code>c</code>和后边的字符<code>p</code>需要进行字节匹配, 没有特殊含义</li><li>通过上面的解释就能明白 <code>\\.cpp$</code> 说的就是以 <code>.cpp</code>结尾的字符串</li></ol></blockquote><h2 id="wc统计文件内容数量" tabindex="-1"><a class="header-anchor" href="#wc统计文件内容数量"><span>wc统计文件内容数量</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>wc [-c -m -l -w] 文件路径</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-c：统计bytes数量 -m：统计字符数量 -l：统计行数 -w：统计单词数量（按空格划分） 文件路径：被统计的文件，<mark>可作为内容输入端口</mark></p><h2 id="管道符" tabindex="-1"><a class="header-anchor" href="#管道符"><span>|管道符</span></a></h2><p>管道符也可嵌套使用 至此有输入输出的命令都可以使用管道符</p><p>将左边命令的结果作为右边命令的输入</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cat text.txt | grap &quot;pink&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>右边的grap命令还缺少一个文件路径使用管道符将cat text.txt作为输入</p><h2 id="echo命令" tabindex="-1"><a class="header-anchor" href="#echo命令"><span>echo命令</span></a></h2><p>在命令行内输出指定内容</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>echo 输出的内容</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>复杂内容可使用“”包裹</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>echo hello world</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在终端中显示hello world</p><p>如果带有空格或\\等特殊符号建议使用双引号包裹，不包裹的话容易被认为是命令的语义</p><h2 id="反引号" tabindex="-1"><a class="header-anchor" href="#反引号"><span>\`反引号</span></a></h2><p>使被它包裹的内容会作为命令去执行</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>echo pwd         在终端中输出pwd</span></span>
<span class="line"><span>echo \`pwd\`       输出pwd的输出</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="重定向符" tabindex="-1"><a class="header-anchor" href="#重定向符"><span>重定向符</span></a></h2><h3 id="和" tabindex="-1"><a class="header-anchor" href="#和"><span>&gt;和&gt;&gt;</span></a></h3><p>只要能产生输出的都能写在重定向符前面</p><p>&gt;：将左侧命令的结果，覆盖写入到符号右侧指定的文件中 &gt;&gt;：将左侧命令的结果，追加写入到符号右侧指定的文件中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>echo &quot;hello world&quot;&gt;test.txt</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>v执行这个命令后test.txt里面原本的内容就被hello world取代了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>echo &quot;hello linux&quot;&gt;&gt;test.txt</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>将hello linux追加到test.txt文件中</p><h2 id="tail命令" tabindex="-1"><a class="header-anchor" href="#tail命令"><span>tail命令</span></a></h2><p>查看文件尾部内容，跟踪文件的最新更改</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>tail [-f -num] Linux路径</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Linux路径：表示被跟踪的文件路径选项 -f：表示持续跟踪（文件中新增的内容会立即显示出来）使用ctrl+c可强制停止 -num：表示查看尾部多少行，不填默认10行</p><h1 id="vi-vim编辑器" tabindex="-1"><a class="header-anchor" href="#vi-vim编辑器"><span>vi\\vim编辑器</span></a></h1><p>![[Pasted image 20240301164342.png]] 底行命令模式会在最后一行显示一个冒号，如果要区分输入模式和命令模式最好的办法是输入一个冒号如果正常输入一个冒号则为输入模式，如果输入的冒号在底部显示出来则为命令模式</p><h2 id="命令模式-command-mode" tabindex="-1"><a class="header-anchor" href="#命令模式-command-mode"><span>命令模式(Command mode)</span></a></h2><p>命令模式下，所敲的按键编辑器都理解为命令，以命令驱动执行不同的功能此模型下，不能自由进行文本编辑。 分别使用vi和vim打开文件</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>vi 文件路径</span></span>
<span class="line"><span>vim 文件路径</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果文件路径表示的文件不存在，那么此命令会用手编辑新文件 如果文件路径表示的文件存在少那么此命令用于编辑已有文件 ![[Pasted image 20240301165332.png]] ![[Pasted image 20240301165556.png]] 重做 . 搜索 / ？</p><h2 id="输入模式-insert-mode" tabindex="-1"><a class="header-anchor" href="#输入模式-insert-mode"><span>输入模式(Insert mode)</span></a></h2><p>也就是所谓的编辑模式、插入模式。此模式下可以对文件内容进行自由编辑</p><h2 id="底行命令模式-last-line-mode" tabindex="-1"><a class="header-anchor" href="#底行命令模式-last-line-mode"><span>底行命令模式(Last line mode)</span></a></h2><p>以:开始，通常用于文件的保存、退出</p><p>![[Pasted image 20240301165919.png]]</p><h1 id="命令行参数" tabindex="-1"><a class="header-anchor" href="#命令行参数"><span>命令行参数</span></a></h1><p>常见的main函数原型：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int main(void)</span></span>
<span class="line"><span>int main(int argc,char* argv[])</span></span>
<span class="line"><span>int main(int argc,char* argv[],char* env[])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>argc：命令行参数的个数，至少为1，./app运行程序也算命令 argv：命令行参数 env：环境变量的指针数组，用于获取系统传递给进程的环境变量的值，一般很少使用</p><p>对于复杂命令选项参数的判断，直接判断argc和argv比较麻烦，可以使用getopt函数来分析命令行参数</p><div class="language-&lt;unistd.h&gt; line-numbers-mode" data-highlighter="shiki" data-ext="&lt;unistd.h&gt;" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int getopt(int argc,char* argv[],const char* optstring);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>optstring：选项字符串，代表命令选项的格式，如果选项字符后跟着一个冒号，表示该选项选择需要一个参数，这个参数可以与选项连着或间隔一个空格。如果选项字符后跟着两个冒号，表示该选项的参数是可选的，即使有参数必须连写，不能间隔空格 如果在命令行参数发现选项字符，则返回该选项字符，如果所有的命令行参数都已经被分析完，则返回-1</p><h1 id="环境变量" tabindex="-1"><a class="header-anchor" href="#环境变量"><span>环境变量</span></a></h1><h2 id="shell变量" tabindex="-1"><a class="header-anchor" href="#shell变量"><span>shell变量</span></a></h2><p>shell是一个特殊的进程，是用户与内核之间的接口，shell启动后拥有多个自己的变量，对环境变量的访问主要包括查看、定义、修改、删除</p><p><strong>查看</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>echo $变量名</span></span>
<span class="line"><span>如： echo $HOME输出登录用户的主目录</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>查看当前shell中所有的环境变量信息可以使用set命令，常用的环境变量有HOME（用户主目录）、PWD（当前工作目录）、PATH（默认可执行程序搜索路径）等，这些变量在用户登录系统后由系统自动设置</p><p><strong>定义和修改</strong> shell允许用户自定义环境变量</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[export] 变量名=变量值1:变量值2......</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>直接定义的环境变量只能被shell本身访问，不能被在shell中启动的其他应用程序访问 如果在该变量前加上export命令，则该变量可以被shell中启动的其他应用程序访问，可以在定义变量的同时使用export命令，也可以在定义变量后单独使用 若要给一个变量添加多个值需要用:隔开 修改环境变量和定义的语法相同，若在修改时保留原变量值的同时添加一些值需要先引用原来的值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export PATH=$PATH:.</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>删除</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>unset 变量名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>使用命令方式对变量做出的改变无论是增删改都是临时的，当系统重新启动后将恢复到改变之前的状况，这是因为Linux系统启动过程中是通过读取系统配置文件来确定各变量的值，使用命令方式对环境变量表的改动并没有记录入文件，所以重新启动后会恢复原状。如果要想在系统重新启动后仍然保持对环境变量的改动需要将改动写入到文件中，在/etc/profile中或用户主目录的.bash_profile。 前者文件中的修改结果所有登录用户都能访问，二后者文件中修改只有某个用户才能访问。</p><h3 id="环境变量相关函数" tabindex="-1"><a class="header-anchor" href="#环境变量相关函数"><span>环境变量相关函数</span></a></h3><div class="language-&lt;stdlib.h&gt; line-numbers-mode" data-highlighter="shiki" data-ext="&lt;stdlib.h&gt;" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//获取环境变量。name要获取的环境变量名。成功获取 环境变量时，返回一个指向环境变量值的指针，如果没有获取环境变量则返回空指针NULL</span></span>
<span class="line"><span>char* getenv(const char* name)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//改变或增加环境变量。string要改变或增加的环境变量表达式，执行成功返回0，失败返回-1</span></span>
<span class="line"><span>int putenv(char* string)</span></span>
<span class="line"><span>//改变或增加一个环境变量。</span></span>
<span class="line"><span>//name环境变量名。value环境变量值。overwrite是否覆盖环境变量原值，0不覆盖，非0覆盖</span></span>
<span class="line"><span>//成功返回0，失败返回-1</span></span>
<span class="line"><span>int setenv(const char* name,const char* value,int overwrite)</span></span>
<span class="line"><span>//删除一个环境变量。</span></span>
<span class="line"><span>//name要删除的环境变量名</span></span>
<span class="line"><span>//成果返回0，失败返回-1并设置errno</span></span>
<span class="line"><span>void unsetenvc(const char* name)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="时间管理" tabindex="-1"><a class="header-anchor" href="#时间管理"><span>时间管理</span></a></h1><p>可以使用date命令获取当前日期和时间 ![[Clip_2024-06-17_21-51-05.png]] 通过time系统调用从系统获取当前的时间得到的时间类型是time_t，但不容易阅读可以使用其他函数转换为字符串或struct tm类型 在通过stime系统调用设置时间也需要转换为time_t类型</p><div class="language-truct line-numbers-mode" data-highlighter="shiki" data-ext="truct" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>struct tm{</span></span>
<span class="line"><span>	int tm_sec;    //秒，范围0~61，2秒闰秒</span></span>
<span class="line"><span>	int tm_min;    //分钟，范围0~59</span></span>
<span class="line"><span>	int tm_hour;    //小时，范围0~23</span></span>
<span class="line"><span>	int tm_mday;    //一个月内的日期，范围1~31</span></span>
<span class="line"><span>	int tm_mon;    //月份，范围0~11</span></span>
<span class="line"><span>	int tm_year;    //年，自1900年开始计算，如：108相当于2008</span></span>
<span class="line"><span>	int tm_wday;    //星期，范围0~6</span></span>
<span class="line"><span>	int tm_yday;    //一年中的日期，范围0~365</span></span>
<span class="line"><span>	int tm_isdst;    //夏令时标记（&gt;0夏令时有效，0无效，-1不可用）</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>获取时间相关函数</strong> time_t本质上就是一个long int型 成功则返回以秒为单位的UNIx时间戳，失败则返回（time_t）-1</p><div class="language-time.h line-numbers-mode" data-highlighter="shiki" data-ext="time.h" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//获取当前日期和时间，可以通过参数获取也可以通过返回值</span></span>
<span class="line"><span>time_t time(time_t* tloc)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>生成随机数 返回一个O-RAND_MAX之间的伪随机数。当前机器环境下，RAND_MAX为int类型的最大值@return int 伪随机数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int rand(void);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>将seed设置为rand（）生成随机数时使用的随机种子，如果没有设置随机种子，rand（)会自动将1作为随机种子 seed随机种子</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void srand(unsigned int seed);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div>`,178)]))}const r=s(d,[["render",l]]),c=JSON.parse('{"path":"/base/linux/1/","title":"1 基础","lang":"zh-CN","frontmatter":{"title":"1 基础","createTime":"2025/06/18 20:42:50","permalink":"/base/linux/1/"},"readingTime":{"minutes":16.88,"words":5063},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/基础/Linux/1 基础.md","headers":[]}');export{r as comp,c as data};
